  function renderEntityPanel(tab){const p=document.getElementById('entity-panel');if(tab==='overview'){p.innerHTML=entityOverview();bindCharts(p);return;}if(tab==='operations'){p.innerHTML=`<section class="ws-surface"><header class="ws-surface-head"><div><h2 class="ws-surface-title">Linked operations</h2><p class="ws-surface-note">Work, checkpoints and cost actions for AST-0421</p></div></header><div class="ws-table-wrap"><table class="ws-table"><thead><tr><th>ID</th><th>Operation</th><th>State</th><th>Owner</th><th>SLA</th></tr></thead><tbody><tr><td><a href="operations.html">OPS-2198</a></td><td>Validate exception and dispatch technician</td><td>${statusBadge('New')}</td><td>Unassigned</td><td class="ws-negative">38 min</td></tr><tr><td>CHK-774</td><td>Horgoš border clearance</td><td>${statusBadge('Success')}</td><td>Automated</td><td>Completed</td></tr><tr><td>WO-4932</td><td>Compressor inspection</td><td>${statusBadge('Scheduled')}</td><td>Field Ops 3</td><td>15:10</td></tr></tbody></table></div></section>`;return;}if(tab==='notes'){p.innerHTML=`<div class="ws-entity-grid" style="grid-template-columns:minmax(0,1fr) minmax(280px,.55fr)"><section class="ws-surface"><header class="ws-surface-head"><h2 class="ws-surface-title">Team notes</h2></header><div class="ws-surface-body"><div class="ws-timeline-item"><i class="ws-timeline-dot"></i><div class="ws-timeline-copy"><b>Eva Kovacevic</b><br>Carrier confirmed the driver is reachable. Keep route active until technician assessment.<time>14:18</time></div></div><div class="ws-timeline-item"><i class="ws-timeline-dot"></i><div class="ws-timeline-copy"><b>Marko Petrovic</b><br>Similar compressor cycling occurred on 10 July; no cargo loss.<time>13:55</time></div></div></div></section><section class="ws-surface"><header class="ws-surface-head"><h2 class="ws-surface-title">Add note</h2></header><div class="ws-surface-body"><label class="ws-eyebrow" for="note-text">Operational context</label><textarea id="note-text" class="ws-input" style="width:100%;min-height:100px;padding-top:9px;resize:vertical" placeholder="Add information useful to the response team"></textarea><button class="ws-btn ws-btn-primary" id="save-note" style="margin-top:9px">Save note</button></div></section></div>`;document.getElementById('save-note').addEventListener('click',()=>{const v=document.getElementById('note-text').value.trim();if(!v){toast('Write a note before saving');return;}document.getElementById('note-count').textContent='3';toast('Note added to asset history');document.getElementById('note-text').value='';});return;}p.innerHTML=`<section class="ws-surface"><header class="ws-surface-head"><div><h2 class="ws-surface-title">Recent audit events</h2><p class="ws-surface-note">Entity-scoped governance history</p></div><a class="ws-btn ws-control-sm" href="audit-log.html">Open full log</a></header><div class="ws-table-wrap"><table class="ws-table"><thead><tr><th>Time</th><th>Actor</th><th>Event</th><th>Result</th></tr></thead><tbody><tr><td class="mono">14:32:08.412</td><td>anomaly-engine</td><td>alert.triggered</td><td>${statusBadge('Warning')}</td></tr><tr><td class="mono">14:18:10.239</td><td>eva.kovacevic</td><td>note.created</td><td>${statusBadge('Success')}</td></tr><tr><td class="mono">13:47:55.091</td><td>telemetry-gateway</td><td>checkpoint.received</td><td>${statusBadge('Success')}</td></tr></tbody></table></div></section>`;}

