  function alertMatches(a){const q=document.getElementById('alert-search').value.toLowerCase(),sev=document.getElementById('alert-severity').value,state=document.getElementById('alert-state').value,owner=document.getElementById('alert-owner').value;return(!q||`${a.id} ${a.title} ${a.entity}`.toLowerCase().includes(q))&&(sev==='all'||a.sev===sev)&&(state==='all'||a.state===state)&&(owner==='all'||a.owner===owner);}
